select 
from artist


        and (
            name like concat('%', #{keyword}, '%')
            or ifnull(tags, '') like concat('%', #{keyword}, '%')
            or ifnull(intro, '') like concat('%', #{keyword}, '%')
            or ifnull(region, '') like concat('%', #{keyword}, '%')
        )


        and gender = #{gender}


        and region = #{region}


        and upper(ifnull(letter, '#')) = upper(#{letter})


        and find_in_set(#{tag}, replace(ifnull(tags, ''), '，', ','))


        and type = #{type}


        and status = #{status}


order by update_time desc, id desc
limit #{offset}, #{limit}

